import {
  Flex,
  Text,
  Grid,
  Image,
  Box,
  useBreakpointValue,
} from "@chakra-ui/react";

const logos = [
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/77hmeEJo3ZPlURCU02fD52/aa37b7f7b52285ba350acac62d8af5c1/illinois-3.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/6XkOucZz6pMLV5DPvXCgCL/1777129a58b0a62b237bd28e9956afe8/duke-3.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/1c6RjBHi3Lqb9QpWxje7iA/b529f909c5230af3210ba2d47d149620/google.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/60SA8pGxPXMmJf4n7umK1H/ccec31bbe2358210bf8391dcba6cd2f1/umich.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/3toC4I7jbWxiedfxiyNjtT/735faeaf976a9692f425f8c3a7d125dc/1000px-IBM_logo.svg.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/FHOd44z40jTFsSSao84AM/d1e357f5650a23bf2936114112d44445/imperial.png",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/4FSFmNXuDIzTvFb7n0v4mK/704ae9e0a7981fb6415f4cb4609bbbb3/stanford.svg",
  "https://d3njjcbhbojbot.cloudfront.net/api/utilities/v1/imageproxy/https://images.ctfassets.net/wp1lcwdav1p1/1ZeiauXe5bPProvfuIo7o2/55d005d42979ab585cdfa01f825b7d4f/penn.svg",
];

const Section2 = () => {
  const columnCount = useBreakpointValue({
    base: 2,
    sm: 3,
    md: 4,
    lg: 6,
  });

  return (
    <Flex direction="column" align="center" py={16} px={5}>
      {/* TEXT */}
      <Text
        fontSize="sm"
        color="gray.500"
        textAlign="center"
        mb={8}
      >
        Trusted by over <b>300+ universities and companies</b>
      </Text>

      {/* LOGO GRID */}
      <Grid
        templateColumns={`repeat(${columnCount}, 1fr)`}
        gap={8}
        alignItems="center"
        w="100%"
        maxW="1000px"
      >
        {logos.map((logo, index) => (
          <Flex key={index} justify="center" align="center">
            <Box
              filter="grayscale(100%)"
              opacity={0.7}
              _hover={{
                filter: "grayscale(0%)",
                opacity: 1,
                transform: "scale(1.05)",
                transition: "0.3s",
              }}
            >
              <Image
                src={logo}
                alt="partner"
                maxH="35px"
                objectFit="contain"
              />
            </Box>
          </Flex>
        ))}
      </Grid>
    </Flex>
  );
};

export default Section2;
